mapper.select:
SELECT * FROM t_grade 
            and student_id = #{studentId} 
            and schedule_id = #{scheduleId} 
            and grade = #{grade}

SELECT g.*
       FROM t_grade g JOIN t_course_schedule cs ON g.schedule_id = cs.schedule_id WHERE
       g.schedule_id = #{scheduleId} AND cs.teacher_id = #{teacherId}

SELECT
   g.*, c.course_name AS courseName FROM t_grade g JOIN t_course_schedule cs ON g.schedule_id =
   cs.schedule_id JOIN t_course c ON cs.course_id = c.course_id WHERE g.student_id = #{studentId}
